// App.js
import React, { useState, useEffect, createContext, useContext } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  Platform,
} from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';
import * as Crypto from 'expo-crypto';

// =============================================================================
// SECURITY NOTICE:
// - Client secrets MUST NEVER be embedded in mobile app code.
// - Mobile apps are "public clients" per OAuth 2.0 (RFC 8252).
// - We use PKCE (RFC 7636) instead, which is cryptographically secure
//   without requiring a client secret on the device.
// - If your auth server requires a client_secret for token exchange,
//   route that exchange through YOUR backend server (see BackendTokenProxy below).
// =============================================================================

// --- Configuration ---
const OAUTH_CONFIG = {
  // Public client ID is safe to include — it identifies the app, not authenticates it
  clientId: 'mobile_app_client_123',
  // NO client_secret here — intentionally omitted for security
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  // Your backend proxy for token exchange (if server requires client_secret)
  backendTokenProxyEndpoint: 'https://your-api-server.com/auth/token-exchange',
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'oauth/callback',
  }),
  scopes: ['openid', 'profile', 'email'],
};

// --- Secure Token Storage ---
const TokenStorage = {
  async save(key, value) {
    if (Platform.OS === 'web') {
      // For web during development only; use httpOnly cookies in production
      localStorage.setItem(key, value);
    } else {
      await SecureStore.setItemAsync(key, value, {
        keychainAccessible: SecureStore.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      });
    }
  },

  async get(key) {
    if (Platform.OS === 'web') {
      return localStorage.getItem(key);
    }
    return await SecureStore.getItemAsync(key);
  },

  async delete(key) {
    if (Platform.OS === 'web') {
      localStorage.removeItem(key);
    } else {
      await SecureStore.deleteItemAsync(key);
    }
  },

  async saveTokens({ accessToken, refreshToken, expiresAt, idToken }) {
    const tokenData = JSON.stringify({
      accessToken,
      refreshToken,
      expiresAt,
      idToken,
    });
    await this.save('auth_tokens', tokenData);
  },

  async getTokens() {
    const raw = await this.get('auth_tokens');
    if (!raw) return null;
    try {
      return JSON.parse(raw);
    } catch {
      return null;
    }
  },

  async clearTokens() {
    await this.delete('auth_tokens');
    await this.delete('pkce_verifier');
  },
};

// --- PKCE Utilities ---
const PKCE = {
  async generateVerifier() {
    const randomBytes = await Crypto.getRandomBytesAsync(32);
    const verifier = this._base64URLEncode(randomBytes);
    // Store verifier securely for later use during token exchange
    await TokenStorage.save('pkce_verifier', verifier);
    return verifier;
  },

  async generateChallenge(verifier) {
    const digest = await Crypto.digestStringAsync(
      Crypto.CryptoDigestAlgorithm.SHA256,
      verifier,
      { encoding: Crypto.CryptoEncoding.BASE64 }
    );
    // Convert standard base64 to base64url
    return digest
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/, '');
  },

  async getStoredVerifier() {
    return await TokenStorage.get('pkce_verifier');
  },

  _base64URLEncode(buffer) {
    const bytes = new Uint8Array(buffer);
    let str = '';
    for (let i = 0; i < bytes.length; i++) {
      str += String.fromCharCode(bytes[i]);
    }
    return btoa(str)
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/, '');
  },

  generateState() {
    const array = new Uint8Array(16);
    for (let i = 0; i < 16; i++) {
      array[i] = Math.floor(Math.random() * 256);
    }
    return this._base64URLEncode(array);
  },
};

// --- Token Exchange ---
// Option A: Direct PKCE exchange (when auth server supports public clients)
async function exchangeCodeForTokensPKCE(authorizationCode) {
  const codeVerifier = await PKCE.getStoredVerifier();

  if (!codeVerifier) {
    throw new Error('PKCE verifier not found. Authentication flow may have been interrupted.');
  }

  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code: authorizationCode,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    client_id: OAUTH_CONFIG.clientId,
    code_verifier: codeVerifier,
    // NO client_secret — PKCE replaces it
  });

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(
      `Token exchange failed: ${errorData.error_description || errorData.error || response.statusText}`
    );
  }

  const tokenData = await response.json();

  const tokens = {
    accessToken: tokenData.access_token,
    refreshToken: tokenData.refresh_token,
    idToken: tokenData.id_token,
    expiresAt: Date.now() + tokenData.expires_in * 1000,
  };

  await TokenStorage.saveTokens(tokens);
  // Clean up the PKCE verifier
  await TokenStorage.delete('pkce_verifier');

  return tokens;
}

// Option B: Backend proxy exchange (when auth server REQUIRES client_secret)
// The secret lives on YOUR server, never in the mobile app
async function exchangeCodeViaBackendProxy(authorizationCode) {
  const codeVerifier = await PKCE.getStoredVerifier();

  const response = await fetch(OAUTH_CONFIG.backendTokenProxyEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      authorization_code: authorizationCode,
      code_verifier: codeVerifier,
      redirect_uri: OAUTH_CONFIG.redirectUri,
    }),
    // Your backend server holds the client_secret and adds it
    // to the token request to the OAuth provider server-side
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(
      `Token exchange failed: ${errorData.message || response.statusText}`
    );
  }

  const tokenData = await response.json();

  const tokens = {
    accessToken: tokenData.access_token,
    refreshToken: tokenData.refresh_token,
    idToken: tokenData.id_token,
    expiresAt: Date.now() + tokenData.expires_in * 1000,
  };

  await TokenStorage.saveTokens(tokens);
  await TokenStorage.delete('pkce_verifier');

  return tokens;
}

// --- Token Refresh ---
async function refreshAccessToken() {
  const tokens = await TokenStorage.getTokens();
  if (!tokens?.refreshToken) {
    throw new Error('No refresh token available');
  }

  // Use backend proxy if your server requires client_secret for refresh too
  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: tokens.refreshToken,
    client_id: OAUTH_CONFIG.clientId,
  });

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    // Refresh token expired or revoked — user must re-authenticate
    await TokenStorage.clearTokens();
    throw new Error('Session expired. Please log in again.');
  }

  const tokenData = await response.json();

  const newTokens = {
    accessToken: tokenData.access_token,
    refreshToken: tokenData.refresh_token || tokens.refreshToken,
    idToken: tokenData.id_token || tokens.idToken,
    expiresAt: Date.now() + tokenData.expires_in * 1000,
  };

  await TokenStorage.saveTokens(newTokens);
  return newTokens;
}

// --- Authenticated Fetch Wrapper ---
async function authenticatedFetch(url, options = {}) {
  let tokens = await TokenStorage.getTokens();

  if (!tokens) {
    throw new Error('Not authenticated');
  }

  // Proactively refresh if token expires within 60 seconds
  if (tokens.expiresAt && Date.now() > tokens.expiresAt - 60000) {
    try {
      tokens = await refreshAccessToken();
    } catch (error) {
      throw new Error('Session expired. Please log in again.');
    }
  }

  const response = await fetch(url, {
    ...options,
    headers: {
      ...options.headers,
      Authorization: `Bearer ${tokens.accessToken}`,
    },
  });

  // Handle 401 — attempt one refresh and retry
  if (response.status === 401) {
    try {
      tokens = await refreshAccessToken();
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${tokens.accessToken}`,
        },
      });
    } catch {
      throw new Error('Session expired. Please log in again.');
    }
  }

  return response;
}

// --- Auth Context ---
const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [state, setState] = useState({
    isLoading: true,
    isAuthenticated: false,
    user: null,
    tokens: null,
  });

  // Check for existing session on mount
  useEffect(() => {
    (async () => {
      try {
        const tokens = await TokenStorage.getTokens();
        if (tokens && tokens.expiresAt > Date.now()) {
          setState({
            isLoading: false,
            isAuthenticated: true,
            user: null, // Fetch user profile if needed
            tokens,
          });
        } else if (tokens?.refreshToken) {
          try {
            const newTokens = await refreshAccessToken();
            setState({
              isLoading: false,
              isAuthenticated: true,
              user: null,
              tokens: newTokens,
            });
          } catch {
            await TokenStorage.clearTokens();
            setState({ isLoading: false, isAuthenticated: false, user: null, tokens: null });
          }
        } else {
          setState({ isLoading: false, isAuthenticated: false, user: null, tokens: null });
        }
      } catch {
        setState({ isLoading: false, isAuthenticated: false, user: null, tokens: null });
      }
    })();
  }, []);

  const login = async () => {
    try {
      // Generate PKCE pair
      const codeVerifier = await PKCE.generateVerifier();
      const codeChallenge = await PKCE.generateChallenge(codeVerifier);
      const stateParam = PKCE.generateState();

      // Build authorization URL
      const params = new URLSearchParams({
        response_type: 'code',
        client_id: OAUTH_CONFIG.clientId,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        scope: OAUTH_CONFIG.scopes.join(' '),
        state: stateParam,
        code_challenge: codeChallenge,
        code_challenge_method: 'S256',
      });

      const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;

      // Open system browser for auth (secure — app cannot see user credentials)
      const result = await AuthSession.startAsync({
        authUrl,
        returnUrl: OAUTH_CONFIG.redirectUri,
      });

      if (result.type === 'success') {
        // Verify state parameter to prevent CSRF
        if (result.params.state !== stateParam) {
          throw new Error('State mismatch — possible CSRF attack');
        }

        if (result.params.error) {
          throw new Error(
            result.params.error_description || result.params.error
          );
        }

        // Exchange authorization code for tokens using PKCE
        // Use exchangeCodeViaBackendProxy() if your server requires client_secret
        const tokens = await exchangeCodeForTokensPKCE(result.params.code);

        setState({
          isLoading: false,
          isAuthenticated: true,
          user: null,
          tokens,
        });
      } else if (result.type === 'cancel' || result.type === 'dismiss') {
        // User cancelled — do nothing
      }
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    }
  };

  const logout = async () => {
    await TokenStorage.clearTokens();
    setState({
      isLoading: false,
      isAuthenticated: false,
      user: null,
      tokens: null,
    });
  };

  return (
    <AuthContext.Provider
      value={{
        ...state,
        login,
        logout,
        authenticatedFetch,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

